#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a[4];
        for (int i = 0; i < 4; i++) {
            scanf("%d", &a[i]);
        }
        qsort(a, 4, sizeof(int), compare);
        if (a[0] == a[1] && a[2] == a[3]) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

